export enum BusinessUserRole {
  Owner = 'owner',
  Admin = 'admin',
  Manager = 'manager',
  Member = 'member',
}

export enum VerificationStatus {
  Pending = 'pending',
  Verified = 'verified',
  Suspended = 'suspended',
}

export enum EquipmentListingStatus {
  Draft = 'draft',
  Active = 'active',
  Paused = 'paused',
  Archived = 'archived',
}

export enum RentalStatus {
  Pending = 'pending',
  Confirmed = 'confirmed',
  Active = 'active',
  Completed = 'completed',
  Cancelled = 'cancelled',
}

export enum PaymentStatus {
  RequiresPaymentMethod = 'requires_payment_method',
  Processing = 'processing',
  Succeeded = 'succeeded',
  Canceled = 'canceled',
  Failed = 'failed',
  Refunded = 'refunded',
  PartiallyRefunded = 'partially_refunded',
}

export enum DepositStatus {
  Pending = 'pending',
  Held = 'held',
  Released = 'released',
  Refunded = 'refunded',
  Failed = 'failed',
}

export enum DeliveryStatus {
  Scheduled = 'scheduled',
  InTransit = 'in_transit',
  Delivered = 'delivered',
  Returned = 'returned',
  Failed = 'failed',
}

export enum ConditionPhase {
  Before = 'before',
  After = 'after',
}

export enum DisputeStatus {
  Open = 'open',
  UnderReview = 'under_review',
  Resolved = 'resolved',
  Rejected = 'rejected',
}

export enum AppRole {
  PlatformAdmin = 'platform_admin',
  BusinessUser = 'business_user',
}

import { createParamDecorator, ExecutionContext } from '@nestjs/common';
import type { Request } from 'express';
import type { JwtPayload } from '../../auth/jwt.strategy';

export const CurrentUser = createParamDecorator(
  (_data: unknown, ctx: ExecutionContext): JwtPayload => {
    const req = ctx.switchToHttp().getRequest<Request & { user?: JwtPayload }>();
    if (!req.user) {
      throw new Error('CurrentUser used without authenticated request');
    }
    return req.user;
  },
);

import { SetMetadata } from '@nestjs/common';
import { AppRole } from '../enums';

export const ROLES_KEY = 'roles';

export const Roles = (...roles: AppRole[]) => SetMetadata(ROLES_KEY, roles);

import { SetMetadata } from '@nestjs/common';

export const IS_PUBLIC_KEY = 'isPublic';

export const Public = () => SetMetadata(IS_PUBLIC_KEY, true);

import {
  CanActivate,
  ExecutionContext,
  ForbiddenException,
  Injectable,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { ROLES_KEY } from '../decorators/roles.decorator';
import { AppRole } from '../enums';
import type { JwtPayload } from '../../auth/jwt.strategy';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private readonly reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const required = this.reflector.getAllAndOverride<AppRole[]>(ROLES_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);
    if (!required?.length) {
      return true;
    }
    const req = context.switchToHttp().getRequest<{ user?: JwtPayload }>();
    const roles = req.user?.roles ?? [];
    const ok = required.some((r) => roles.includes(r));
    if (!ok) {
      throw new ForbiddenException('Insufficient role');
    }
    return true;
  }
}

import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
  Logger,
} from '@nestjs/common';
import type { Request, Response } from 'express';

@Catch()
export class AllExceptionsFilter implements ExceptionFilter {
  private readonly logger = new Logger(AllExceptionsFilter.name);

  catch(exception: unknown, host: ArgumentsHost): void {
    const ctx = host.switchToHttp();
    const res = ctx.getResponse<Response>();
    const req = ctx.getRequest<Request>();

    const status =
      exception instanceof HttpException
        ? exception.getStatus()
        : HttpStatus.INTERNAL_SERVER_ERROR;

    const message =
      exception instanceof HttpException
        ? exception.getResponse()
        : 'Internal server error';

    this.logger.warn(
      `${req.method} ${req.url} → ${status} ${typeof message === 'string' ? message : JSON.stringify(message)}`,
    );

    res.status(status).json({
      statusCode: status,
      path: req.url,
      message,
      timestamp: new Date().toISOString(),
    });
  }
}

import { Injectable, UnauthorizedException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PassportStrategy } from '@nestjs/passport';
import { passportJwtSecret } from 'jwks-rsa';
import { ExtractJwt, Strategy } from 'passport-jwt';
import { AppRole } from '../common/enums';

export interface JwtPayload {
  /** Azure AD B2C subject */
  sub: string;
  oid?: string;
  emails?: string[];
  /** Optional app registrations / claims */
  roles: AppRole[];
  /** Resolved internal user id after sync (attached by middleware later) */
  userId?: string;
}

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy, 'azure-b2c-jwt') {
  constructor(private readonly config: ConfigService) {
    const tenant = config.get<string>('azureAdB2C.tenant', '');
    const policy = config.get<string>('azureAdB2C.policy', '');
    const clientId = config.get<string>('azureAdB2C.clientId', '');
    const configuredJwks = process.env.AZURE_AD_B2C_JWKS_URI;
    const jwksUri =
      configuredJwks?.trim() ||
      `https://${tenant}.b2clogin.com/${tenant}.onmicrosoft.com/${policy}/discovery/v2.0/keys`;

    const issuer = config.get<string>('azureAdB2C.issuer', '');

    const devSecret = config.get<string>('jwtDevSecret', '');
    const useDev = config.get<string>('env') === 'development' && !!devSecret;

    super(
      useDev
        ? {
            jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
            ignoreExpiration: false,
            secretOrKey: devSecret,
            audience: clientId || undefined,
            issuer: issuer || undefined,
          }
        : {
            jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
            ignoreExpiration: false,
            secretOrKeyProvider: passportJwtSecret({
              cache: true,
              rateLimit: true,
              jwksUri,
            }),
            audience: clientId,
            issuer,
            algorithms: ['RS256'],
          },
    );
  }

  validate(payload: Record<string, unknown>): JwtPayload {
    const sub = String(payload.sub ?? payload.oid ?? '');
    if (!sub) {
      throw new UnauthorizedException('Token missing subject');
    }
    const rawRoles = payload.roles ?? (payload as { extension_Roles?: string[] }).extension_Roles;
    const roles: AppRole[] = [];
    if (Array.isArray(rawRoles)) {
      for (const r of rawRoles) {
        if (r === AppRole.PlatformAdmin || r === 'platform_admin')
          roles.push(AppRole.PlatformAdmin);
      }
    }
    if (!roles.length) {
      roles.push(AppRole.BusinessUser);
    }
    return {
      sub,
      oid: payload.oid as string | undefined,
      emails: payload.emails as string[] | undefined,
      roles,
    };
  }
}

import { ExecutionContext, Injectable } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { AuthGuard } from '@nestjs/passport';
import { IS_PUBLIC_KEY } from '../common/decorators/public.decorator';

@Injectable()
export class JwtAuthGuard extends AuthGuard('azure-b2c-jwt') {
  constructor(private readonly reflector: Reflector) {
    super();
  }

  canActivate(context: ExecutionContext) {
    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);
    if (isPublic) {
      return true;
    }
    return super.canActivate(context);
  }
}

import { Module } from '@nestjs/common';
import { ConfigModule, ConfigService } from '@nestjs/config';
import { JwtModule } from '@nestjs/jwt';
import { PassportModule } from '@nestjs/passport';
import { JwtStrategy } from './jwt.strategy';

@Module({
  imports: [
    PassportModule.register({ defaultStrategy: 'azure-b2c-jwt' }),
    ConfigModule,
    JwtModule.registerAsync({
      imports: [ConfigModule],
      useFactory: (config: ConfigService) => ({
        secret: config.get<string>('jwtDevSecret', 'dev'),
      }),
      inject: [ConfigService],
    }),
  ],
  providers: [JwtStrategy],
  exports: [PassportModule, JwtStrategy],
})
export class AuthModule {}

