import {
  Column,
  CreateDateColumn,
  DeleteDateColumn,
  Entity,
  OneToMany,
  PrimaryGeneratedColumn,
  UpdateDateColumn,
} from 'typeorm';
import { BusinessUser } from './business-user.entity';
import { EquipmentCondition } from './equipment-condition.entity';
import { Review } from './review.entity';
import { Dispute } from './dispute.entity';

@Entity({ name: 'users' })
export class User {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({ name: 'email', type: 'nvarchar', length: 320 })
  email: string;

  @Column({ name: 'display_name', type: 'nvarchar', length: 200 })
  displayName: string;

  @Column({ name: 'azure_ad_b2c_oid', type: 'nvarchar', length: 64, nullable: true })
  azureAdB2cOid: string | null;

  @Column({ name: 'password_hash', type: 'nvarchar', length: 512, nullable: true })
  passwordHash: string | null;

  @CreateDateColumn({ name: 'created_at', type: 'datetime2' })
  createdAt: Date;

  @UpdateDateColumn({ name: 'updated_at', type: 'datetime2' })
  updatedAt: Date;

  @DeleteDateColumn({ name: 'deleted_at', type: 'datetime2', nullable: true })
  deletedAt: Date | null;

  @OneToMany(() => BusinessUser, (m) => m.user)
  businessMemberships: BusinessUser[];

  @OneToMany(() => EquipmentCondition, (c) => c.inspector)
  inspections: EquipmentCondition[];

  @OneToMany(() => Review, (r) => r.reviewer)
  reviews: Review[];

  @OneToMany(() => Dispute, (d) => d.raisedBy)
  disputesRaised: Dispute[];

  @OneToMany(() => Dispute, (d) => d.resolvedBy)
  disputesResolved: Dispute[];
}

import {
  Column,
  CreateDateColumn,
  DeleteDateColumn,
  Entity,
  OneToMany,
  PrimaryGeneratedColumn,
  UpdateDateColumn,
} from 'typeorm';
import { VerificationStatus } from '../common/enums';
import { BusinessUser } from './business-user.entity';
import { Equipment } from './equipment.entity';
import { Rental } from './rental.entity';

@Entity({ name: 'businesses' })
export class Business {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({ name: 'legal_name', type: 'nvarchar', length: 300 })
  legalName: string;

  @Column({ name: 'tax_id', type: 'nvarchar', length: 64, nullable: true })
  taxId: string | null;

  @Column({
    name: 'verification_status',
    type: 'varchar',
    length: 32,
    default: VerificationStatus.Pending,
  })
  verificationStatus: VerificationStatus;

  @Column({
    name: 'stripe_connect_account_id',
    type: 'nvarchar',
    length: 64,
    nullable: true,
  })
  stripeConnectAccountId: string | null;

  @CreateDateColumn({ name: 'created_at', type: 'datetime2' })
  createdAt: Date;

  @UpdateDateColumn({ name: 'updated_at', type: 'datetime2' })
  updatedAt: Date;

  @DeleteDateColumn({ name: 'deleted_at', type: 'datetime2', nullable: true })
  deletedAt: Date | null;

  @OneToMany(() => BusinessUser, (m) => m.business)
  members: BusinessUser[];

  @OneToMany(() => Equipment, (e) => e.business)
  equipment: Equipment[];

  @OneToMany(() => Rental, (r) => r.renterBusiness)
  rentalsAsRenter: Rental[];

  @OneToMany(() => Rental, (r) => r.supplierBusiness)
  rentalsAsSupplier: Rental[];
}

import {
  Column,
  CreateDateColumn,
  Entity,
  JoinColumn,
  ManyToOne,
  PrimaryGeneratedColumn,
  Unique,
  UpdateDateColumn,
} from 'typeorm';
import { BusinessUserRole } from '../common/enums';
import { User } from './user.entity';
import { Business } from './business.entity';

@Entity({ name: 'business_users' })
@Unique(['user', 'business'])
export class BusinessUser {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @ManyToOne(() => User, (u) => u.businessMemberships, { onDelete: 'NO ACTION' })
  @JoinColumn({ name: 'user_id' })
  user: User;

  @Column({ name: 'user_id', type: 'uniqueidentifier' })
  userId: string;

  @ManyToOne(() => Business, (b) => b.members, { onDelete: 'NO ACTION' })
  @JoinColumn({ name: 'business_id' })
  business: Business;

  @Column({ name: 'business_id', type: 'uniqueidentifier' })
  businessId: string;

  @Column({ name: 'role', type: 'varchar', length: 32 })
  role: BusinessUserRole;

  @CreateDateColumn({ name: 'created_at', type: 'datetime2' })
  createdAt: Date;

  @UpdateDateColumn({ name: 'updated_at', type: 'datetime2' })
  updatedAt: Date;
}

import {
  Column,
  CreateDateColumn,
  DeleteDateColumn,
  Entity,
  JoinColumn,
  ManyToOne,
  OneToMany,
  PrimaryGeneratedColumn,
  UpdateDateColumn,
} from 'typeorm';
import { EquipmentListingStatus } from '../common/enums';
import { Business } from './business.entity';
import { EquipmentImage } from './equipment-image.entity';
import { Rental } from './rental.entity';

@Entity({ name: 'equipment' })
export class Equipment {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @ManyToOne(() => Business, (b) => b.equipment, { onDelete: 'NO ACTION' })
  @JoinColumn({ name: 'business_id' })
  business: Business;

  @Column({ name: 'business_id', type: 'uniqueidentifier' })
  businessId: string;

  @Column({ name: 'title', type: 'nvarchar', length: 300 })
  title: string;

  @Column({ name: 'description', type: 'nvarchar', length: 2000, nullable: true })
  description: string | null;

  @Column({ name: 'daily_rate_cents', type: 'int' })
  dailyRateCents: number;

  @Column({ name: 'currency', type: 'char', length: 3, default: 'USD' })
  currency: string;

  @Column({
    name: 'listing_status',
    type: 'varchar',
    length: 32,
    default: EquipmentListingStatus.Draft,
  })
  listingStatus: EquipmentListingStatus;

  @CreateDateColumn({ name: 'created_at', type: 'datetime2' })
  createdAt: Date;

  @UpdateDateColumn({ name: 'updated_at', type: 'datetime2' })
  updatedAt: Date;

  @DeleteDateColumn({ name: 'deleted_at', type: 'datetime2', nullable: true })
  deletedAt: Date | null;

  @OneToMany(() => EquipmentImage, (i) => i.equipment)
  images: EquipmentImage[];

  @OneToMany(() => Rental, (r) => r.equipment)
  rentals: Rental[];
}

import {
  Column,
  CreateDateColumn,
  Entity,
  JoinColumn,
  ManyToOne,
  PrimaryGeneratedColumn,
  UpdateDateColumn,
} from 'typeorm';
import { Equipment } from './equipment.entity';

@Entity({ name: 'equipment_images' })
export class EquipmentImage {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @ManyToOne(() => Equipment, (e) => e.images, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'equipment_id' })
  equipment: Equipment;

  @Column({ name: 'equipment_id', type: 'uniqueidentifier' })
  equipmentId: string;

