import { Injectable, OnModuleInit } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

/** Optional Application Insights bootstrap — connection string from Key Vault / App Settings */
@Injectable()
export class AppInsightsService implements OnModuleInit {
  constructor(private readonly config: ConfigService) {}

  onModuleInit(): void {
    const conn = this.config.get<string>('appInsights', '');
    if (!conn) {
      return;
    }
    try {
      // eslint-disable-next-line @typescript-eslint/no-require-imports
      const appInsights = require('applicationinsights') as typeof import('applicationinsights');
      appInsights
        .setup(conn)
        .setAutoCollectRequests(true)
        .setAutoCollectExceptions(true)
        .setAutoCollectDependencies(true)
        .start();
    } catch {
      /* optional dependency at runtime */
    }
  }
}

import { Injectable, InternalServerErrorException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import {
  BlobSASPermissions,
  BlobServiceClient,
  ContainerClient,
  generateBlobSASQueryParameters,
  StorageSharedKeyCredential,
} from '@azure/storage-blob';
import { randomUUID } from 'crypto';

export type BlobContainerKey = 'equipment' | 'conditions' | 'disputes' | 'deliveries';

@Injectable()
export class BlobStorageService {
  private readonly credential: StorageSharedKeyCredential;
  private readonly serviceClient: BlobServiceClient;

  constructor(private readonly config: ConfigService) {
    const name = this.config.get<string>('blob.accountName', '');
    const key = this.config.get<string>('blob.accountKey', '');
    if (!name || !key) {
      throw new InternalServerErrorException('Blob storage is not configured');
    }
    this.credential = new StorageSharedKeyCredential(name, key);
    this.serviceClient = new BlobServiceClient(
      `https://${name}.blob.core.windows.net`,
      this.credential,
    );
  }

  private container(key: BlobContainerKey): ContainerClient {
    const map = this.config.get<Record<BlobContainerKey, string>>('blob.containers')!;
    const containerName = map[key];
    return this.serviceClient.getContainerClient(containerName);
  }

  /**
   * Returns a time-limited write URL for direct client upload, plus the blob path to persist.
   */
  async createUploadSas(
    key: BlobContainerKey,
    extension: string,
    ttlMinutes = 15,
  ): Promise<{ uploadUrl: string; blobPath: string }> {
    const ext = extension.replace(/^\./, '').slice(0, 8);
    const blobPath = `${randomUUID()}.${ext}`;
    const container = this.container(key);
    const blobClient = container.getBlockBlobClient(blobPath);
    const startsOn = new Date(Date.now() - 60_000);
    const expiresOn = new Date(Date.now() + ttlMinutes * 60_000);
    const sas = generateBlobSASQueryParameters(
      {
        containerName: container.containerName,
        blobName: blobPath,
        permissions: BlobSASPermissions.parse('cw'),
        startsOn,
        expiresOn,
      },
      this.credential,
    ).toString();
    return { uploadUrl: `${blobClient.url}?${sas}`, blobPath };
  }

  /** Read-only URL for authorized API consumers (short-lived). */
  async createReadSas(key: BlobContainerKey, blobPath: string, ttlMinutes = 60): Promise<string> {
    const container = this.container(key);
    const blobClient = container.getBlobClient(blobPath);
    const startsOn = new Date(Date.now() - 60_000);
    const expiresOn = new Date(Date.now() + ttlMinutes * 60_000);
    const sas = generateBlobQSASQueryParametersRead(container.containerName, blobPath, startsOn, expiresOn, this.credential);
    return `${blobClient.url}?${sas}`;
  }
}

function generateBlobQSASQueryParametersRead(
  containerName: string,
  blobName: string,
  startsOn: Date,
  expiresOn: Date,
  credential: StorageSharedKeyCredential,
): string {
  return generateBlobSASQueryParameters(
    {
      containerName,
      blobName,
      permissions: BlobSASPermissions.parse('r'),
      startsOn,
      expiresOn,
    },
    credential,
  ).toString();
}

