import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { ServiceBusClient, ServiceBusSender } from '@azure/service-bus';

@Injectable()
export class ServiceBusPublisher {
  private readonly logger = new Logger(ServiceBusPublisher.name);
  private client: ServiceBusClient | null = null;
  private sender: ServiceBusSender | null = null;

  constructor(private readonly config: ConfigService) {
    const conn = this.config.get<string>('serviceBus.connectionString', '');
    const topic = this.config.get<string>('serviceBus.rentalEventsTopic', '');
    if (conn && topic) {
      this.client = new ServiceBusClient(conn);
      this.sender = this.client.createSender(topic);
    }
  }

  async publishRentalEvent(body: Record<string, unknown>): Promise<void> {
    if (!this.sender) {
      this.logger.debug('Service Bus not configured; skip publish');
      return;
    }
    await this.sender.sendMessages({ body, contentType: 'application/json' });
  }

  async onModuleDestroy(): Promise<void> {
    await this.sender?.close();
    await this.client?.close();
  }
}

import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import Stripe from 'stripe';

@Injectable()
export class StripeService {
  private readonly stripe: Stripe;

  constructor(config: ConfigService) {
    const key = config.get<string>('stripe.secretKey', '');
    this.stripe = new Stripe(key, { apiVersion: '2024-12-18.acacia' });
  }

  /**
   * Stripe Connect: destination charges — platform captures rental fee; separate PI for deposit (manual capture).
   */
  async createRentalPaymentIntent(params: {
    amountCents: number;
    currency: string;
    connectedAccountId: string;
    applicationFeeCents: number;
    rentalId: string;
    captureMethod?: 'automatic' | 'manual';
  }): Promise<Stripe.PaymentIntent> {
    return this.stripe.paymentIntents.create({
      amount: params.amountCents,
      currency: params.currency.toLowerCase(),
      capture_method: params.captureMethod ?? 'manual',
      automatic_payment_methods: { enabled: true },
      application_fee_amount: params.applicationFeeCents,
      transfer_data: { destination: params.connectedAccountId },
      metadata: { rentalId: params.rentalId },
    });
  }

  async createDepositPaymentIntent(params: {
    amountCents: number;
    currency: string;
    rentalId: string;
    captureMethod?: 'automatic' | 'manual';
  }): Promise<Stripe.PaymentIntent> {
    return this.stripe.paymentIntents.create({
      amount: params.amountCents,
      currency: params.currency.toLowerCase(),
      capture_method: params.captureMethod ?? 'manual',
      automatic_payment_methods: { enabled: true },
      metadata: { rentalId: params.rentalId, kind: 'deposit' },
    });
  }

  async capturePaymentIntent(paymentIntentId: string): Promise<Stripe.PaymentIntent> {
    return this.stripe.paymentIntents.capture(paymentIntentId);
  }

  async cancelPaymentIntent(paymentIntentId: string): Promise<Stripe.PaymentIntent> {
    return this.stripe.paymentIntents.cancel(paymentIntentId);
  }

  async refundCharge(chargeId: string, amountCents?: number): Promise<Stripe.Refund> {
