        synchronize: false,
        logging: config.get<string>('env') === 'development',
        options: {
          encrypt: config.get<boolean>('database.encrypt'),
          trustServerCertificate: config.get<boolean>(
            'database.trustServerCertificate',
          ),
          enableArithAbort: true,
        },
        extra: {
          options: {
            encrypt: config.get<boolean>('database.encrypt'),
